/**
 * MedX dropdown runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Action menus for row operations, bulk actions, and user account controls.
 */
const DROPDOWN_ACTIONS = Object.freeze({
  inventoryRow: [
    { id: "view", label: "View details", icon: "eye", shortcut: "Enter" },
    { id: "edit", label: "Edit item", icon: "pencil", shortcut: "E" },
    { id: "transfer", label: "Transfer stock", icon: "arrow-right" },
    { id: "separator-1", type: "separator" },
    { id: "quarantine", label: "Quarantine lot", icon: "alert-triangle", variant: "warning" },
    { id: "delete", label: "Delete record", icon: "trash", variant: "destructive", shortcut: "Del" },
  ],
  bulkActions: [
    { id: "export", label: "Export CSV", icon: "download" },
    { id: "print-labels", label: "Print labels", icon: "printer" },
    { id: "assign-warehouse", label: "Assign warehouse", icon: "warehouse" },
    { id: "separator-1", type: "separator" },
    { id: "archive", label: "Archive selected", icon: "archive" },
  ],
  userMenu: [
    { id: "profile", label: "Profile", icon: "user" },
    { id: "settings", label: "Settings", icon: "settings" },
    { id: "separator-1", type: "separator" },
    { id: "sign-out", label: "Sign out", icon: "log-out", variant: "destructive" },
  ],
});

const dropdownInstances = new Map();

function buildMenuItems(menuKey, context = {}) {
  const template = DROPDOWN_ACTIONS[menuKey];
  if (!template) return [];
  return template
    .filter((item) => {
      if (item.type === "separator") return true;
      if (item.id === "quarantine" && !context.canQuarantine) return false;
      if (item.id === "delete" && !context.canDelete) return false;
      return true;
    })
    .map((item) => ({ ...item, menuKey }));
}

function createDropdown(config) {
  const id = config.id ?? `medx-dropdown-${dropdownInstances.size + 1}`;
  const instance = {
    id,
    menuKey: config.menuKey,
    items: buildMenuItems(config.menuKey, config.context ?? {}),
    open: false,
    anchor: config.anchor ?? "bottom-end",
    selectedIndex: -1,
    context: config.context ?? {},
    onAction: typeof config.onAction === "function" ? config.onAction : null,
  };
  dropdownInstances.set(id, instance);
  return instance;
}

function openDropdown(id) {
  const instance = dropdownInstances.get(id);
  if (!instance) return false;
  instance.open = true;
  instance.openedAt = Date.now();
  instance.selectedIndex = instance.items.findIndex((i) => i.type !== "separator");
  return true;
}

function closeDropdown(id) {
  const instance = dropdownInstances.get(id);
  if (!instance) return false;
  instance.open = false;
  instance.selectedIndex = -1;
  return true;
}

function executeDropdownAction(id, actionId) {
  const instance = dropdownInstances.get(id);
  if (!instance) return null;
  const item = instance.items.find((i) => i.id === actionId);
  if (!item || item.type === "separator") return null;
  const result = { dropdownId: id, actionId, item, executedAt: Date.now() };
  if (instance.onAction) instance.onAction(result);
  closeDropdown(id);
  return result;
}

function handleDropdownKeydown(id, key) {
  const instance = dropdownInstances.get(id);
  if (!instance || !instance.open) return null;
  const actionable = instance.items.filter((i) => i.type !== "separator");
  if (key === "ArrowDown" || key === "ArrowUp") {
    const delta = key === "ArrowDown" ? 1 : -1;
    let idx = instance.selectedIndex + delta;
    if (idx < 0) idx = actionable.length - 1;
    if (idx >= actionable.length) idx = 0;
    instance.selectedIndex = instance.items.indexOf(actionable[idx]);
    return { type: "navigate", index: instance.selectedIndex };
  }
  if (key === "Enter" && instance.selectedIndex >= 0) {
    const item = instance.items[instance.selectedIndex];
    return executeDropdownAction(id, item.id);
  }
  if (key === "Escape") {
    closeDropdown(id);
    return { type: "close" };
  }
  return null;
}

async function runMedxDropdown() {
  console.log("[medx:ui:dropdown] runtime initialized");
  console.log(`[medx:ui:dropdown] menus=${Object.keys(DROPDOWN_ACTIONS).length}`);

  const actions = [];
  const rowMenu = createDropdown({
    menuKey: "inventoryRow",
    context: { canQuarantine: true, canDelete: false },
    onAction: (r) => actions.push(r.actionId),
  });
  const bulkMenu = createDropdown({ menuKey: "bulkActions" });

  openDropdown(rowMenu.id);
  handleDropdownKeydown(rowMenu.id, "ArrowDown");
  executeDropdownAction(rowMenu.id, "view");

  console.log(`[medx:ui:dropdown] instances=${dropdownInstances.size}`);
  console.log("[medx:ui:dropdown] executed", actions.join(","));
  console.log(`[medx:ui:dropdown] bulkItems=${bulkMenu.items.length}`);
  console.log("[medx:ui:dropdown] bootstrap complete");
}

module.exports = runMedxDropdown;
